// nodes/noteNode.js — Sticky note / comment node (no handles)
import { BaseNode } from '../components/BaseNode';

const config = {
  title: 'Note',
  icon: '🗒️',
  color: 'var(--pf-yellow)',
  fields: [
    { key: 'content', label: 'Note', type: 'textarea',
      defaultValue: '', placeholder: 'Add a comment or annotation...' },
  ],
  inputs:  [],
  outputs: [],
};

export const NoteNode = (props) => <BaseNode {...props} config={config} />;
